protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed — Cosmos DB throws at startup in EF Core 9.
    // Manage indexing via the container's indexing policy (Azure Portal / Bicep).

    modelBuilder.Entity<Product>().ToContainer("Products");

    // Preserve EF Core 8 discriminator property name ("Discriminator" → "$type" in EF 9)
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // Preserve EF Core 8 compound id format ("Product|123" → "123" in EF 9)
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

