using System.Linq;

class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator is safe because we configured
        // HasDiscriminator<string>("Discriminator") to keep the EF Core 8 name.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Sync I/O (ToList) throws in EF Core 9 Cosmos provider; use async.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

